// Refs: 'WH Receive Invoice Data'
const input = $input.first().json;

const errors = [];

if (!input.customer_name || input.customer_name.trim() === '') {
  errors.push('customer_name is required');
}

if (!input.customer_email || !input.customer_email.includes('@')) {
  errors.push('customer_email is required and must be valid');
}

if (!input.items || !Array.isArray(input.items) || input.items.length === 0) {
  errors.push('items array is required and must contain at least one item');
} else {
  input.items.forEach((item, i) => {
    if (!item.label) errors.push(`items[${i}].label is required`);
    if (!item.quantity || item.quantity <= 0) errors.push(`items[${i}].quantity must be > 0`);
    if (!item.unit_price || item.unit_price <= 0) errors.push(`items[${i}].unit_price must be > 0`);
  });
}

if (errors.length > 0) {
  throw new Error('Validation failed: ' + errors.join('; '));
}

return [{
  json: {
    customer_name: input.customer_name.trim(),
    customer_email: input.customer_email.trim().toLowerCase(),
    customer_address: input.customer_address || '',
    customer_postal_code: input.customer_postal_code || '00000',
    customer_city: input.customer_city || 'Non renseigné',
    customer_country: input.customer_country || 'FR',
    items: input.items.map(item => ({
      label: item.label,
      quantity: item.quantity,
      unit_price: item.unit_price,
      vat_rate: item.vat_rate || 'FR_200'
    })),
    due_date: input.due_date || new Date(Date.now() + 30 * 24 * 60 * 60 * 1000).toISOString().split('T')[0],
    currency: input.currency || 'EUR',
    payment_conditions: input.payment_conditions || '30_days',
    reference: input.reference || null,
    send_email: input.send_email || false,
    notification_email: input.notification_email || null
  }
}];

