// Refs: 'Set Customer ID', 'Code Validate Payload'
const data = $('Code Validate Payload').first().json;
const customerId = $('Set Customer ID').first().json.customer_id;

const invoiceLines = data.items.map(item => ({
  label: item.label,
  quantity: item.quantity,
  unit: 'piece',
  raw_currency_unit_price: String(item.unit_price.toFixed(2)),
  vat_rate: item.vat_rate
}));

const today = new Date().toISOString().split('T')[0];

const payload = {
  customer_id: customerId,
  date: today,
  deadline: data.due_date,
  currency: data.currency,
  invoice_lines: invoiceLines,
  draft: false
};

if (data.reference) {
  payload.external_reference = data.reference;
}

return [{ json: payload }];

// Refs: 'PL Create Invoice', 'Code Validate Payload'
const invoice = $('PL Create Invoice').first().json;
const data = $('Code Validate Payload').first().json;

const message = [
  `New invoice created in Pennylane`,
  ``,
  `Customer: ${data.customer_name}`,
  `Invoice: ${invoice.invoice_number}`,
  `Amount: ${invoice.currency_amount_before_tax} EUR HT`,
  `Total TTC: ${invoice.currency_amount} EUR`,
  `Due date: ${data.due_date}`,
  `Status: ${invoice.status}`,
  data.reference ? `Reference: ${data.reference}` : '',
  ``,
  `View: ${invoice.public_file_url || 'N/A'}`
].filter(Boolean).join('\n');

return [{
  json: {
    message,
    invoice_id: invoice.id,
    invoice_number: invoice.invoice_number,
    amount: invoice.currency_amount,
    customer_name: data.customer_name,
    public_url: invoice.public_file_url || null
  }
}];
